This is definitely a kernel regression. Following c program can be used to reproduce:
```c
#include <sys/socket.h>
#include <sys/un.h>
#include <stdlib.h>
#include <stdio.h>
#include <netinet/in.h>
#include <unistd.h>

int main(int argc, char *argv[])
{
    int ret, sock1, sock2;
    struct sockaddr_in6 addr;
    struct sockaddr_in addr2;

    sock1 = socket(AF_INET6, SOCK_STREAM, 0);
    if (sock1 == -1)
    {
        perror("socket1");
        exit(1);
    }
    sock2 = socket(AF_INET, SOCK_STREAM, 0);
    if (sock2 == -1)
    {
        perror("socket2");
        exit(1);
    }

    memset(&addr, 0, sizeof(addr));
    addr.sin6_family = AF_INET6;
    addr.sin6_addr = in6addr_any;
    addr.sin6_port = htons(8080);

    memset(&addr2, 0, sizeof(addr2));
    addr2.sin_family = AF_INET;
    addr2.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
    addr2.sin_port = htons(8080);

    ret = bind(sock1, (struct sockaddr *)&addr, sizeof(addr));
    if (ret == -1)
    {
        perror("bind1");
        exit(1);
    }
    printf("bind1 ret: %d\n", ret);

    if ((listen(sock1, 5)) != 0)
    {
        perror("listen1");
        exit(1);
    }

    ret = bind(sock2, (struct sockaddr *)&addr2, sizeof(addr2));
    if (ret == -1)
    {
        perror("bind2");
        exit(1);
    }
    printf("bind2 ret: %d\n", ret);

    if ((listen(sock2, 5)) != 0)
    {
        perror("listen2");
        exit(1);
    }

    pause();

    return 0;
}
```

If second bind fails then it works correctly but if it does not fail the second bind returns 0 and the same port is bound twice.
